export const core_MeasurementReadiness = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/core/measurement-readiness.json",
  "title": "Measurement Readiness",
  "description": "Per-product assessment of whether the buyer's event source setup is sufficient for the product's optimization capabilities. Sellers evaluate this in the context of the buyer's account — the same product may show different readiness for different buyers depending on their event source configuration.",
  "type": "object",
  "properties": {
    "status": {
      "$ref": "/schemas/3.0.6/enums/assessment-status.json",
      "description": "Overall measurement readiness level for this product given the buyer's event setup. 'insufficient' means the product cannot optimize effectively with the current setup."
    },
    "required_event_types": {
      "type": "array",
      "description": "Event types this product needs for effective optimization. Buyers should ensure their event sources cover these types.",
      "items": {
        "$ref": "/schemas/3.0.6/enums/event-type.json"
      },
      "minItems": 1
    },
    "missing_event_types": {
      "type": "array",
      "description": "Event types this product requires that the buyer has not configured. Empty or absent when all required types are covered.",
      "items": {
        "$ref": "/schemas/3.0.6/enums/event-type.json"
      }
    },
    "issues": {
      "type": "array",
      "description": "Actionable issues preventing full measurement readiness. Sellers should limit to the top 3-5 most actionable items. Buyer agents should sort by severity rather than relying on array position.",
      "items": {
        "$ref": "/schemas/3.0.6/core/diagnostic-issue.json"
      }
    },
    "notes": {
      "type": "string",
      "description": "Seller explanation of the readiness assessment, recommendations for improvement, or context about what the buyer needs to change."
    }
  },
  "required": [
    "status"
  ],
  "additionalProperties": true
} as const;

export const core_MeasurementTerms = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/core/measurement-terms.json",
  "title": "Measurement Terms",
  "description": "Billing measurement and makegood terms for media buys. Declares who counts the billing metric and what remedies apply when thresholds are breached. Appears on products (seller defaults), package requests (buyer proposals), and confirmed packages (agreed terms). All fields are optional — presence indicates the term is declared or proposed.",
  "type": "object",
  "properties": {
    "billing_measurement": {
      "type": "object",
      "description": "Which vendor's count of the billing metric governs invoicing. The billing metric is determined by the pricing_model on the selected pricing_option (e.g., impressions for CPM, completed views for CPCV).",
      "properties": {
        "vendor": {
          "$ref": "/schemas/3.0.6/core/brand-ref.json",
          "description": "Vendor whose measurement of the billing metric is authoritative for invoicing (e.g., { domain: 'campaignmanager.google.com' } for buyer's DCM, { domain: 'admanager.google.com' } for seller's GAM)."
        },
        "max_variance_percent": {
          "type": "number",
          "minimum": 0,
          "exclusiveMaximum": 100,
          "description": "Maximum acceptable variance between the billing vendor's count and the other party's count before resolution is triggered (e.g., 10 means a 10% divergence triggers review)."
        },
        "measurement_window": {
          "type": "string",
          "description": "Which measurement maturation stage the billing metric is reconciled against. References a window_id from the product's reporting_capabilities.measurement_windows. Examples: 'c7' for broadcast TV guarantees (live + 7 days DVR), 'final' for DOOH after IVT/fraud-check processing, 'post_sivt' for digital after sophisticated invalid-traffic filtering, 'downloads_30d' for podcast. When absent, billing is based on the seller's standard reporting without windowed maturation.",
          "examples": [
            "live",
            "c3",
            "c7",
            "tentative",
            "final",
            "post_ivt",
            "post_sivt",
            "downloads_30d"
          ]
        }
      },
      "required": [
        "vendor"
      ],
      "additionalProperties": true
    },
    "makegood_policy": {
      "type": "object",
      "description": "Remedies available when a performance standard or billing measurement variance is breached. Seller declares which remedy types they support. When a breach occurs, the seller proposes a remedy from this menu; the buyer accepts or disputes.",
      "properties": {
        "available_remedies": {
          "type": "array",
          "description": "Remedy types the seller supports. Ordered by seller preference (first = preferred). Seller proposes from this list when a breach occurs; buyer accepts or disputes.",
          "items": {
            "$ref": "/schemas/3.0.6/enums/makegood-remedy.json"
          },
          "minItems": 1,
          "uniqueItems": true
        }
      },
      "required": [
        "available_remedies"
      ],
      "additionalProperties": true
    }
  },
  "additionalProperties": true
} as const;

export const core_MeasurementWindow = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/core/measurement-window.json",
  "title": "Measurement Window",
  "description": "A measurement maturation stage for any channel where billing-grade data is produced in phases rather than arriving final on day one. Each window represents an accumulation or processing stage with its own expected availability. Examples: broadcast/linear TV (live → C3 → C7 DVR accumulation), DOOH (tentative plays → post-IVT/fraud-check final), digital (raw impressions → GIVT filtered → SIVT filtered), podcast (7-day downloads → 30-day downloads), audio/radio (tentative → diary/panel-certified). Sellers whose data is final on first delivery omit this.",
  "type": "object",
  "properties": {
    "window_id": {
      "type": "string",
      "maxLength": 50,
      "description": "Identifier for this maturation stage. Standard broadcast values: 'live' (real-time viewers only), 'c3' (live + 3 days time-shifted), 'c7' (live + 7 days time-shifted). Standard values for other channels include 'tentative' (provisional data available quickly), 'final' (post-processing certified data), 'post_ivt' (digital after invalid-traffic filtering), 'post_sivt' (digital after sophisticated-IVT filtering), 'downloads_7d' / 'downloads_30d' (podcast download maturation). Sellers may define custom IDs.",
      "examples": [
        "live",
        "c3",
        "c7",
        "tentative",
        "final",
        "post_ivt",
        "downloads_30d"
      ]
    },
    "description": {
      "type": "string",
      "maxLength": 500,
      "description": "Human-readable description of what this window measures",
      "examples": [
        "Live broadcast impressions only",
        "Live plus 7 days of time-shifted viewing",
        "Tentative plays before IVT and fraud-check processing",
        "Final plays after IVT and fraud-check processing",
        "Impressions after sophisticated invalid-traffic filtering"
      ]
    },
    "duration_days": {
      "type": "integer",
      "description": "Number of days of accumulation included in this window before processing begins. For broadcast, this is DVR accumulation (0 = live only, 3 = live + 3 days DVR, 7 = live + 7 days DVR). For channels without an accumulation period (DOOH tentative→final, digital IVT filtering), this is 0 — maturation is entirely vendor processing time captured in expected_availability_days.",
      "minimum": 0
    },
    "expected_availability_days": {
      "type": "integer",
      "description": "Expected number of days after delivery before this window's data is available from the measurement vendor. Captures accumulation time plus vendor processing time. Examples: broadcast C7 from VideoAmp ~22 days (7-day accumulation + ~15-day processing); DOOH tentative plays same-day; DOOH final (post-IVT/fraud-check) ~1 day; digital post-SIVT ~2–3 days.",
      "minimum": 0
    },
    "is_guarantee_basis": {
      "type": "boolean",
      "description": "Whether this window is the basis for delivery guarantees, reconciliation, and invoicing. A product typically has one guarantee basis window (e.g., C7 for most US broadcast, post-IVT final for DOOH). Buyers reconcile against the guarantee basis window's final numbers."
    }
  },
  "required": [
    "window_id",
    "duration_days"
  ],
  "additionalProperties": true
} as const;

