export const core_Proposal = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/core/proposal.json",
  "title": "Proposal",
  "description": "A proposed media plan with budget allocations across products. Represents the publisher's strategic recommendation for how to structure a campaign based on the brief. Proposals are actionable - buyers can execute them directly via create_media_buy by providing the proposal_id.",
  "type": "object",
  "properties": {
    "proposal_id": {
      "type": "string",
      "description": "Unique identifier for this proposal. Used to execute it via create_media_buy.",
      "maxLength": 255
    },
    "name": {
      "type": "string",
      "description": "Human-readable name for this media plan proposal",
      "maxLength": 500
    },
    "description": {
      "type": "string",
      "description": "Explanation of the proposal strategy and what it achieves",
      "maxLength": 2000
    },
    "allocations": {
      "type": "array",
      "description": "Budget allocations across products. Allocation percentages MUST sum to 100. Publishers are responsible for ensuring the sum equals 100; buyers SHOULD validate this before execution.",
      "items": {
        "$ref": "/schemas/3.0.6/core/product-allocation.json"
      },
      "minItems": 1
    },
    "proposal_status": {
      "$ref": "/schemas/3.0.6/enums/proposal-status.json",
      "description": "Lifecycle status of this proposal. When absent, the proposal is ready to buy (backward compatible). 'draft' means indicative pricing — finalize via refine before purchasing. 'committed' means firm pricing with inventory reserved until expires_at."
    },
    "expires_at": {
      "type": "string",
      "format": "date-time",
      "description": "When this proposal expires and can no longer be executed. For draft proposals, indicates when indicative pricing becomes stale. For committed proposals, indicates when the inventory hold lapses — the buyer must call create_media_buy before this time."
    },
    "insertion_order": {
      "$ref": "/schemas/3.0.6/core/insertion-order.json",
      "description": "Formal insertion order attached to a committed proposal. Present when the seller requires a signed agreement before the media buy can proceed. The buyer references the io_id in io_acceptance on create_media_buy."
    },
    "total_budget_guidance": {
      "type": "object",
      "description": "Optional budget guidance for this proposal",
      "properties": {
        "min": {
          "type": "number",
          "description": "Minimum recommended budget",
          "minimum": 0
        },
        "recommended": {
          "type": "number",
          "description": "Recommended budget for optimal performance",
          "minimum": 0
        },
        "max": {
          "type": "number",
          "description": "Maximum budget before diminishing returns",
          "minimum": 0
        },
        "currency": {
          "type": "string",
          "description": "ISO 4217 currency code"
        }
      },
      "additionalProperties": true
    },
    "brief_alignment": {
      "type": "string",
      "description": "Explanation of how this proposal aligns with the campaign brief",
      "maxLength": 2000
    },
    "forecast": {
      "$ref": "/schemas/3.0.6/core/delivery-forecast.json",
      "description": "Aggregate forecasted delivery metrics for the entire proposal. When both proposal-level and allocation-level forecasts are present, the proposal-level forecast is authoritative for total delivery estimation."
    },
    "ext": {
      "$ref": "/schemas/3.0.6/core/ext.json"
    }
  },
  "required": [
    "proposal_id",
    "name",
    "allocations"
  ],
  "additionalProperties": true
} as const;

export const core_ProtocolEnvelope = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/core/protocol-envelope.json",
  "title": "Protocol Envelope",
  "description": "Standard envelope structure for AdCP task responses. This envelope is added by the protocol layer (MCP, A2A, REST) and wraps the task-specific response payload. Task response schemas should NOT include these fields - they are protocol-level concerns.",
  "type": "object",
  "properties": {
    "context_id": {
      "type": "string",
      "description": "Session/conversation identifier for tracking related operations across multiple task invocations. Managed by the protocol layer to maintain conversational context."
    },
    "task_id": {
      "type": "string",
      "description": "Unique identifier for tracking asynchronous operations. Present when a task requires extended processing time. Used to query task status and retrieve results when complete.",
      "x-entity": "task"
    },
    "status": {
      "$ref": "/schemas/3.0.6/enums/task-status.json",
      "description": "Current task execution state. Indicates whether the task is completed, in progress (working), submitted for async processing, failed, or requires user input. Managed by the protocol layer. Agents MUST NOT emit the legacy task_status or response_status fields alongside this field — the status field is the single authoritative task state."
    },
    "message": {
      "type": "string",
      "description": "Human-readable summary of the task result. Provides natural language explanation of what happened, suitable for display to end users or for AI agent comprehension. Generated by the protocol layer based on the task response."
    },
    "timestamp": {
      "type": "string",
      "format": "date-time",
      "description": "ISO 8601 timestamp when the response was generated. Useful for debugging, logging, cache validation, and tracking async operation progress."
    },
    "replayed": {
      "type": "boolean",
      "description": "Set to true when this response is a cached replay returned for an idempotency_key that was already processed. Set to false (or omitted) when the request was executed fresh. Buyers use this to distinguish cached replays from new executions — matters for billing reconciliation, audit logs, and any downstream system that assumes exactly-once event semantics. Only present on responses to mutating requests that carry idempotency_key.",
      "default": false
    },
    "push_notification_config": {
      "$ref": "/schemas/3.0.6/core/push-notification-config.json",
      "description": "Push notification configuration for async task updates (A2A and REST protocols). Echoed from the request to confirm webhook settings. Specifies URL, authentication scheme (Bearer or HMAC-SHA256), and credentials. MCP uses progress notifications instead of webhooks."
    },
    "governance_context": {
      "type": "string",
      "description": "Governance context token issued by a governance agent during check_governance. Buyers attach it to governed purchase requests (media buys, rights acquisitions, signal activations, creative services); sellers persist it and include it on all subsequent governance calls for that action's lifecycle.\n\nValue format: in 3.0 governance agents MUST emit a compact JWS per the AdCP JWS profile (see Security — Signed Governance Context). Sellers MAY verify; sellers that do not verify MUST persist and forward the token unchanged. In 3.1 all sellers MUST verify. Non-JWS values from pre-3.0 governance agents are deprecated.\n\nThis is the primary correlation key for audit and reporting across the governance lifecycle.",
      "minLength": 1,
      "maxLength": 4096,
      "pattern": "^[\\x20-\\x7E]+$"
    },
    "payload": {
      "type": "object",
      "description": "The actual task-specific response data. This is the content defined in individual task response schemas (e.g., get-products-response.json, create-media-buy-response.json). Contains only domain-specific data without protocol-level fields.",
      "additionalProperties": true
    }
  },
  "required": [
    "status",
    "payload"
  ],
  "additionalProperties": true,
  "not": {
    "anyOf": [
      {
        "required": [
          "task_status"
        ]
      },
      {
        "required": [
          "response_status"
        ]
      }
    ]
  },
  "examples": [
    {
      "description": "Synchronous task response with immediate results",
      "data": {
        "context_id": "ctx_abc123",
        "status": "completed",
        "message": "Found 3 products matching your criteria for CTV inventory in California",
        "timestamp": "2025-10-14T14:25:30Z",
        "payload": {
          "products": [
            {
              "product_id": "ctv_premium_ca",
              "name": "CTV Premium - California",
              "description": "Premium connected TV inventory across California",
              "pricing": {
                "model": "cpm",
                "amount": 45,
                "currency": "USD"
              }
            }
          ]
        }
      }
    },
    {
      "description": "Asynchronous task response with pending operation",
      "data": {
        "context_id": "ctx_def456",
        "task_id": "task_789",
        "status": "submitted",
        "message": "Media buy creation submitted. Processing will take approximately 5-10 minutes. You'll receive updates via webhook.",
        "timestamp": "2025-10-14T14:30:00Z",
        "push_notification_config": {
          "url": "https://buyer.example.com/webhooks/adcp",
          "authentication": {
            "schemes": [
              "HMAC-SHA256"
            ],
            "credentials": "shared_secret_exchanged_during_onboarding_min_32_chars"
          }
        },
        "payload": {
          "account": {
            "account_id": "acct_123"
          }
        }
      }
    },
    {
      "description": "Task response requiring user input",
      "data": {
        "context_id": "ctx_ghi789",
        "task_id": "task_101",
        "status": "input-required",
        "message": "This media buy requires manual approval. Please review the terms and confirm to proceed.",
        "timestamp": "2025-10-14T14:32:15Z",
        "payload": {
          "media_buy_id": "mb_123456",
          "packages": [
            {
              "package_id": "pkg_001"
            }
          ],
          "errors": [
            {
              "code": "APPROVAL_REQUIRED",
              "message": "Budget exceeds auto-approval threshold",
              "severity": "warning"
            }
          ]
        }
      }
    },
    {
      "description": "Idempotent replay — same key and payload as a prior request within the replay window",
      "data": {
        "context_id": "ctx_abc123",
        "status": "completed",
        "message": "Returning cached response for idempotency_key (already processed)",
        "timestamp": "2025-10-14T14:35:00Z",
        "replayed": true,
        "payload": {
          "media_buy_id": "mb_01HW7J8K9P0Q1R2S3T4U5V6W7X"
        }
      }
    },
    {
      "description": "Failed task response with error details",
      "data": {
        "context_id": "ctx_jkl012",
        "status": "failed",
        "message": "Unable to create media buy due to invalid targeting parameters",
        "timestamp": "2025-10-14T14:28:45Z",
        "payload": {
          "errors": [
            {
              "code": "INVALID_TARGETING",
              "message": "Geographic targeting codes are invalid",
              "field": "targeting.geo_countries",
              "severity": "error"
            }
          ]
        }
      }
    }
  ],
  "notes": [
    "Task response schemas (e.g., get-products-response.json) define ONLY the payload structure",
    "Protocol implementations (MCP, A2A, REST) wrap the payload with this envelope",
    "Different protocols may use different serialization formats but maintain the same semantic structure",
    "MCP may represent this via tool response content fields and metadata",
    "A2A may represent this via assistant messages with structured data",
    "REST may use HTTP headers for status/task metadata and JSON body for payload",
    "The envelope ensures consistent behavior across all protocol implementations"
  ]
} as const;

export const core_Provenance = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/core/provenance.json",
  "title": "Provenance",
  "description": "Declares how content was produced, whether AI was involved, and what disclosure obligations apply. Attaches to creative manifests, individual assets, or content-standards artifacts. When present at multiple levels, the most specific provenance object replaces the inherited one entirely (no field-level merging). Provenance is a claim by the declaring party — receiving parties should verify claims independently via their own detection tools.",
  "type": "object",
  "properties": {
    "digital_source_type": {
      "$ref": "/schemas/3.0.6/enums/digital-source-type.json",
      "description": "IPTC-aligned classification of AI involvement in producing this content"
    },
    "ai_tool": {
      "type": "object",
      "description": "AI system used to generate or modify this content. Aligns with IPTC 2025.1 AI metadata fields and C2PA claim_generator.",
      "properties": {
        "name": {
          "type": "string",
          "description": "Name of the AI tool or model (e.g., 'DALL-E 3', 'Stable Diffusion XL', 'Gemini')"
        },
        "version": {
          "type": "string",
          "description": "Version identifier for the AI tool or model (e.g., '25.1', '0125', '2.1'). For generative models, use the model version rather than the API version."
        },
        "provider": {
          "type": "string",
          "description": "Organization that provides the AI tool (e.g., 'OpenAI', 'Stability AI', 'Google')"
        }
      },
      "required": [
        "name"
      ],
      "additionalProperties": true
    },
    "human_oversight": {
      "type": "string",
      "description": "Level of human involvement in the AI-assisted creation process",
      "enum": [
        "none",
        "prompt_only",
        "selected",
        "edited",
        "directed"
      ],
      "enumDescriptions": {
        "none": "Fully automated with no human involvement in generation",
        "prompt_only": "Human provided the prompt or instructions but did not review outputs",
        "selected": "Human selected from multiple AI-generated candidates",
        "edited": "Human edited or refined AI-generated output",
        "directed": "Human directed the creative process with AI as an assistive tool"
      }
    },
    "declared_by": {
      "type": "object",
      "description": "Party declaring this provenance. Identifies who attached the provenance claim, enabling receiving parties to assess trust.",
      "properties": {
        "agent_url": {
          "type": "string",
          "format": "uri",
          "description": "URL of the agent or service that declared this provenance"
        },
        "role": {
          "type": "string",
          "enum": [
            "creator",
            "advertiser",
            "agency",
            "platform",
            "tool"
          ],
          "description": "Role of the declaring party in the supply chain",
          "enumDescriptions": {
            "creator": "The party that created or generated the content",
            "advertiser": "The brand or advertiser that owns the content",
            "agency": "Agency acting on behalf of the advertiser",
            "platform": "Ad platform or publisher that processed the content",
            "tool": "Automated tool or service that attached provenance metadata"
          }
        }
      },
      "required": [
        "role"
      ],
      "additionalProperties": true
    },
    "declared_at": {
      "type": "string",
      "format": "date-time",
      "description": "When this provenance claim was made (ISO 8601). Distinct from created_time, which records when the content itself was produced. A provenance claim may be attached well after content creation, for example when retroactively declaring AI involvement for regulatory compliance."
    },
    "created_time": {
      "type": "string",
      "format": "date-time",
      "description": "When this content was created or generated (ISO 8601)"
    },
    "c2pa": {
      "type": "object",
      "description": "C2PA Content Credentials reference. Links to the cryptographic provenance manifest for this content. Because file-level C2PA bindings break during ad-tech transcoding, this URL reference preserves the chain of provenance through the supply chain.",
      "properties": {
        "manifest_url": {
          "type": "string",
          "format": "uri",
          "description": "URL to the C2PA manifest store for this content"
        }
      },
      "required": [
        "manifest_url"
      ],
      "additionalProperties": true
    },
    "disclosure": {
      "type": "object",
      "description": "Regulatory disclosure requirements for this content. Indicates whether AI disclosure is required and under which jurisdictions.",
      "properties": {
        "required": {
          "type": "boolean",
          "description": "Whether AI disclosure is required for this content based on applicable regulations"
        },
        "jurisdictions": {
          "type": "array",
          "description": "Jurisdictions where disclosure obligations apply",
          "items": {
            "type": "object",
            "properties": {
              "country": {
                "type": "string",
                "description": "ISO 3166-1 alpha-2 country code (e.g., 'US', 'DE', 'CN')"
              },
              "region": {
                "type": "string",
                "description": "Sub-national region code (e.g., 'CA' for California, 'BY' for Bavaria)"
              },
              "regulation": {
                "type": "string",
                "description": "Regulation identifier (e.g., 'eu_ai_act_article_50', 'ca_sb_942', 'cn_deep_synthesis')"
              },
              "label_text": {
                "type": "string",
                "description": "Required disclosure label text for this jurisdiction, in the local language"
              },
              "render_guidance": {
                "type": "object",
                "description": "How the disclosure should be rendered for this jurisdiction. Expresses the declaring party's intent for persistence and position based on regulatory requirements. Publishers control actual rendering but governance agents can audit whether guidance was followed.",
                "minProperties": 1,
                "properties": {
                  "persistence": {
                    "$ref": "/schemas/3.0.6/enums/disclosure-persistence.json",
                    "description": "How long the disclosure must persist during content playback or display"
                  },
                  "min_duration_ms": {
                    "type": "integer",
                    "minimum": 1,
                    "description": "Minimum display duration in milliseconds for initial persistence. Recommended when persistence is initial — without it, the duration is at the publisher's discretion. At serve time the publisher reads this from provenance since the brief is not available."
                  },
                  "positions": {
                    "type": "array",
                    "description": "Preferred disclosure positions in priority order. The first position a format supports should be used.",
                    "items": {
                      "$ref": "/schemas/3.0.6/enums/disclosure-position.json"
                    },
                    "minItems": 1,
                    "uniqueItems": true
                  },
                  "ext": {
                    "$ref": "/schemas/3.0.6/core/ext.json"
                  }
                },
                "additionalProperties": true
              }
            },
            "required": [
              "country",
              "regulation"
            ],
            "additionalProperties": true
          },
          "minItems": 1
        }
      },
      "required": [
        "required"
      ],
      "additionalProperties": true
    },
    "verification": {
      "type": "array",
      "description": "Third-party verification or detection results for this content. Multiple services may independently evaluate the same content. Provenance is a claim — verification results attached by the declaring party are supplementary. The enforcing party (e.g., seller/publisher) should run its own verification via get_creative_features or calibrate_content.",
      "minItems": 1,
      "items": {
        "type": "object",
        "properties": {
          "verified_by": {
            "type": "string",
            "description": "Name of the verification service (e.g., 'DoubleVerify', 'Hive Moderation', 'Reality Defender')"
          },
          "verified_time": {
            "type": "string",
            "format": "date-time",
            "description": "When the verification was performed (ISO 8601)"
          },
          "result": {
            "type": "string",
            "enum": [
              "authentic",
              "ai_generated",
              "ai_modified",
              "inconclusive"
            ],
            "description": "Verification outcome"
          },
          "confidence": {
            "type": "number",
            "minimum": 0,
            "maximum": 1,
            "description": "Confidence score of the verification result (0.0 to 1.0)"
          },
          "details_url": {
            "type": "string",
            "format": "uri",
            "description": "URL to the full verification report"
          }
        },
        "required": [
          "verified_by",
          "result"
        ],
        "additionalProperties": true
      }
    },
    "ext": {
      "$ref": "/schemas/3.0.6/core/ext.json"
    }
  },
  "additionalProperties": true
} as const;

export const core_PublisherPropertySelector = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/core/publisher-property-selector.json",
  "title": "Publisher Property Selector",
  "description": "Selects properties from a publisher's adagents.json. Used for both product definitions and agent authorization. Supports three selection patterns: all properties, specific IDs, or by tags.",
  "discriminator": {
    "propertyName": "selection_type"
  },
  "oneOf": [
    {
      "type": "object",
      "description": "Select all properties from the publisher domain",
      "properties": {
        "publisher_domain": {
          "type": "string",
          "description": "Domain where publisher's adagents.json is hosted (e.g., 'cnn.com')",
          "pattern": "^[a-z0-9]([a-z0-9-]*[a-z0-9])?(\\.[a-z0-9]([a-z0-9-]*[a-z0-9])?)*$"
        },
        "selection_type": {
          "type": "string",
          "const": "all",
          "description": "Discriminator indicating all properties from this publisher are included"
        }
      },
      "required": [
        "publisher_domain",
        "selection_type"
      ],
      "additionalProperties": true
    },
    {
      "type": "object",
      "description": "Select specific properties by ID",
      "properties": {
        "publisher_domain": {
          "type": "string",
          "description": "Domain where publisher's adagents.json is hosted (e.g., 'cnn.com')",
          "pattern": "^[a-z0-9]([a-z0-9-]*[a-z0-9])?(\\.[a-z0-9]([a-z0-9-]*[a-z0-9])?)*$"
        },
        "selection_type": {
          "type": "string",
          "const": "by_id",
          "description": "Discriminator indicating selection by specific property IDs"
        },
        "property_ids": {
          "type": "array",
          "description": "Specific property IDs from the publisher's adagents.json",
          "items": {
            "$ref": "/schemas/3.0.6/core/property-id.json"
          },
          "minItems": 1
        }
      },
      "required": [
        "publisher_domain",
        "selection_type",
        "property_ids"
      ],
      "additionalProperties": true
    },
    {
      "type": "object",
      "description": "Select properties by tag membership",
      "properties": {
        "publisher_domain": {
          "type": "string",
          "description": "Domain where publisher's adagents.json is hosted (e.g., 'cnn.com')",
          "pattern": "^[a-z0-9]([a-z0-9-]*[a-z0-9])?(\\.[a-z0-9]([a-z0-9-]*[a-z0-9])?)*$"
        },
        "selection_type": {
          "type": "string",
          "const": "by_tag",
          "description": "Discriminator indicating selection by property tags"
        },
        "property_tags": {
          "type": "array",
          "description": "Property tags from the publisher's adagents.json. Selector covers all properties with these tags",
          "items": {
            "$ref": "/schemas/3.0.6/core/property-tag.json"
          },
          "minItems": 1
        }
      },
      "required": [
        "publisher_domain",
        "selection_type",
        "property_tags"
      ],
      "additionalProperties": true
    }
  ]
} as const;

export const core_PushNotificationConfig = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/core/push-notification-config.json",
  "title": "Push Notification Config",
  "description": "Webhook configuration for asynchronous task notifications. Uses A2A-compatible PushNotificationConfig structure. By default, webhooks are signed with the AdCP RFC 9421 profile (see docs/building/implementation/security.mdx#webhook-callbacks) — the seller signs outbound with a key published at the jwks_uri on its own brand.json `agents[]` entry and the buyer verifies against that JWKS, so no shared secret crosses the wire. The optional `authentication` block selects the legacy Bearer or HMAC-SHA256 fallback for compatibility with receivers that have not yet adopted the 9421 profile; this fallback is deprecated and will be removed in AdCP 4.0. Note: the `idempotency_key` that receivers dedup on lives inside the webhook **payload** body (see docs/building/implementation/webhooks.mdx#reliability and the mcp-webhook-payload schema), not in this configuration object — this schema only describes the receiver-side transport config sent to the seller. This schema is designed for composition via allOf - consuming schemas should define their own additionalProperties constraints.",
  "type": "object",
  "properties": {
    "url": {
      "type": "string",
      "format": "uri",
      "description": "Webhook endpoint URL for task status notifications"
    },
    "token": {
      "type": "string",
      "description": "Optional client-provided token for webhook validation. Echoed back in webhook payload to validate request authenticity.",
      "minLength": 16
    },
    "authentication": {
      "type": "object",
      "description": "Legacy authentication configuration (A2A-compatible). Opts the seller into Bearer or HMAC-SHA256 signing instead of the default RFC 9421 webhook profile. Deprecated; removed in AdCP 4.0. **Precedence is a switch, not a fallback:** presence of this block selects the legacy scheme; absence selects 9421. A seller MUST NOT sign the same webhook both ways, and a buyer MUST NOT attempt 'try 9421 first, fall back to HMAC' verification — signature mode is determined solely by whether this block was present at registration time. The seller's baseline 9421 webhook-signing key published at its brand.json `agents[]` `jwks_uri` does not override this selector; it is always discoverable but only used when `authentication` is omitted. See docs/building/implementation/security.mdx#webhook-callbacks for the full precedence and downgrade-resistance rules (including the `webhook_mode_mismatch` rejection a buyer MUST apply when a received webhook's signing mode does not match the registered mode).",
      "properties": {
        "schemes": {
          "type": "array",
          "description": "Array of authentication schemes. Supported: ['Bearer'] for simple token auth, ['HMAC-SHA256'] for legacy shared-secret signing. Both are deprecated; new integrations SHOULD omit `authentication` and use the RFC 9421 webhook profile.",
          "items": {
            "$ref": "/schemas/3.0.6/enums/auth-scheme.json"
          },
          "minItems": 1,
          "maxItems": 1
        },
        "credentials": {
          "type": "string",
          "description": "Credentials for the legacy scheme. For Bearer: token sent in Authorization header. For HMAC-SHA256: shared secret used to generate signature. Minimum 32 characters. Exchanged out-of-band during onboarding.",
          "minLength": 32
        }
      },
      "required": [
        "schemes",
        "credentials"
      ],
      "additionalProperties": false
    }
  },
  "required": [
    "url"
  ]
} as const;

