export const core_RightsConstraint = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/core/rights-constraint.json",
  "title": "Rights Constraint",
  "description": "Rights metadata attached to a creative manifest. Each entry represents constraints from a single rights holder. A creative may combine multiple rights constraints (e.g., talent likeness + music license). For v1, rights constraints are informational metadata — the buyer/orchestrator manages creative lifecycle against these terms.",
  "type": "object",
  "properties": {
    "rights_id": {
      "type": "string",
      "description": "Rights grant identifier from the acquire_rights response"
    },
    "rights_agent": {
      "type": "object",
      "description": "The agent that granted these rights",
      "properties": {
        "url": {
          "type": "string",
          "format": "uri",
          "description": "MCP endpoint URL of the rights agent"
        },
        "id": {
          "type": "string",
          "description": "Agent identifier"
        }
      },
      "required": [
        "url",
        "id"
      ]
    },
    "valid_from": {
      "type": "string",
      "format": "date-time",
      "description": "Start of the rights validity period"
    },
    "valid_until": {
      "type": "string",
      "format": "date-time",
      "description": "End of the rights validity period. Creative should not be served after this time."
    },
    "uses": {
      "type": "array",
      "description": "Rights uses covered by this constraint",
      "items": {
        "$ref": "/schemas/3.0.6/enums/right-use.json"
      },
      "minItems": 1
    },
    "countries": {
      "type": "array",
      "description": "Countries where this creative may be served under these rights (ISO 3166-1 alpha-2). If omitted, no country restriction. When both countries and excluded_countries are present, the effective set is countries minus excluded_countries.",
      "items": {
        "type": "string",
        "pattern": "^[A-Z]{2}$"
      }
    },
    "excluded_countries": {
      "type": "array",
      "description": "Countries excluded from rights availability (ISO 3166-1 alpha-2). Use when the grant is worldwide except specific markets.",
      "items": {
        "type": "string",
        "pattern": "^[A-Z]{2}$"
      }
    },
    "impression_cap": {
      "type": "integer",
      "minimum": 1,
      "description": "Maximum total impressions allowed for the full validity period (valid_from to valid_until). This is the absolute cap across all creatives using this rights grant, not a per-creative or per-period limit."
    },
    "right_type": {
      "$ref": "/schemas/3.0.6/enums/right-type.json",
      "description": "Type of rights (talent, music, etc.). Helps identify constraints when a creative combines multiple rights types."
    },
    "approval_status": {
      "type": "string",
      "enum": [
        "pending",
        "approved",
        "rejected"
      ],
      "description": "Approval status from the rights holder at manifest creation time (snapshot, not a live value)"
    },
    "verification_url": {
      "type": "string",
      "format": "uri",
      "description": "URL where downstream supply chain participants can verify this rights grant is active. Returns HTTP 200 with the current grant status, or 404 if revoked. Enables SSPs and verification vendors to confirm rights before serving."
    },
    "ext": {
      "$ref": "/schemas/3.0.6/core/ext.json"
    }
  },
  "required": [
    "rights_id",
    "rights_agent",
    "uses"
  ],
  "additionalProperties": true
} as const;

export const core_SellerAgentRef = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/core/seller-agent-ref.json",
  "title": "Seller Agent Reference",
  "description": "Structured reference to a seller agent. The canonical identifier is the agent's URL as declared in the property publisher's adagents.json `authorized_agents[].url`. The optional `id` slot is reserved for a future registry-assigned stable identifier; it is not used today. This shape mirrors `format-id` and `ProviderEntry` — URL-first, with an ID slot for forward compatibility.",
  "x-status": "experimental",
  "type": "object",
  "properties": {
    "agent_url": {
      "type": "string",
      "format": "uri",
      "description": "The seller agent's API endpoint URL as declared in the property publisher's adagents.json `authorized_agents[].url`. MUST use the `https://` scheme. Receivers compare this URL against the `authorized_agents` list using the AdCP URL canonicalization rules — not byte-equality — and reject mismatches with `seller_not_authorized`. See docs/reference/url-canonicalization."
    },
    "id": {
      "type": "string",
      "description": "Reserved for a future registry-assigned stable seller identifier. Not used today — senders MUST NOT populate this field until a registry is defined. When a future release populates both `agent_url` and `id`, `agent_url` remains authoritative and `id` is advisory.",
      "pattern": "^[a-zA-Z0-9_-]+$",
      "minLength": 1
    }
  },
  "required": [
    "agent_url"
  ],
  "additionalProperties": false,
  "examples": [
    {
      "agent_url": "https://agent.acme.example"
    }
  ]
} as const;

export const core_SignalDefinition = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/core/signal-definition.json",
  "title": "Signal Definition",
  "description": "Definition of a signal in a data provider's catalog, published via adagents.json",
  "type": "object",
  "properties": {
    "id": {
      "type": "string",
      "pattern": "^[a-zA-Z0-9_-]+$",
      "description": "Signal identifier within this data provider's catalog"
    },
    "name": {
      "type": "string",
      "description": "Human-readable signal name",
      "minLength": 1,
      "maxLength": 255
    },
    "description": {
      "type": "string",
      "description": "Detailed description of what this signal represents and how it's derived",
      "maxLength": 2000
    },
    "value_type": {
      "$ref": "/schemas/3.0.6/enums/signal-value-type.json",
      "description": "The data type of this signal's values"
    },
    "tags": {
      "type": "array",
      "description": "Tags for grouping and filtering signals within the catalog",
      "items": {
        "type": "string",
        "pattern": "^[a-z0-9_-]+$"
      }
    },
    "allowed_values": {
      "type": "array",
      "description": "For categorical signals, the valid values users can be assigned",
      "items": {
        "type": "string"
      },
      "minItems": 1
    },
    "restricted_attributes": {
      "type": "array",
      "description": "Restricted attribute categories this signal touches. Data providers SHOULD declare these so governance agents can structurally match signals against a plan's restricted_attributes without relying on semantic inference from the signal name or description.",
      "items": {
        "$ref": "/schemas/3.0.6/enums/restricted-attribute.json"
      },
      "minItems": 1
    },
    "policy_categories": {
      "type": "array",
      "description": "Policy categories this signal is sensitive for (e.g., a children's interest signal declares ['children_directed']). Governance agents match these against a plan's policy_categories to flag sensitive data usage.",
      "items": {
        "type": "string"
      },
      "minItems": 1
    },
    "range": {
      "type": "object",
      "description": "For numeric signals, the valid value range",
      "properties": {
        "min": {
          "type": "number",
          "description": "Minimum value"
        },
        "max": {
          "type": "number",
          "description": "Maximum value"
        },
        "unit": {
          "type": "string",
          "description": "Unit of measurement (e.g., 'score', 'dollars', 'years')"
        }
      },
      "required": [
        "min",
        "max"
      ]
    }
  },
  "required": [
    "id",
    "name",
    "value_type"
  ],
  "additionalProperties": true
} as const;

