export const core_TasksListRequest = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/core/tasks-list-request.json",
  "title": "Tasks List Request",
  "description": "Request parameters for listing and filtering async tasks across all AdCP protocols with state reconciliation capabilities",
  "type": "object",
  "properties": {
    "adcp_major_version": {
      "type": "integer",
      "description": "The AdCP major version the buyer's payloads conform to. Sellers validate against their supported major_versions and return VERSION_UNSUPPORTED if unsupported. When omitted, the seller assumes its highest supported version.",
      "minimum": 1,
      "maximum": 99
    },
    "filters": {
      "type": "object",
      "description": "Filter criteria for querying tasks",
      "properties": {
        "protocol": {
          "$ref": "/schemas/3.0.6/enums/adcp-protocol.json",
          "description": "Filter by single AdCP protocol"
        },
        "protocols": {
          "type": "array",
          "description": "Filter by multiple AdCP protocols",
          "items": {
            "$ref": "/schemas/3.0.6/enums/adcp-protocol.json"
          },
          "minItems": 1
        },
        "status": {
          "$ref": "/schemas/3.0.6/enums/task-status.json",
          "description": "Filter by single task status"
        },
        "statuses": {
          "type": "array",
          "description": "Filter by multiple task statuses",
          "items": {
            "$ref": "/schemas/3.0.6/enums/task-status.json"
          },
          "minItems": 1
        },
        "task_type": {
          "$ref": "/schemas/3.0.6/enums/task-type.json",
          "description": "Filter by single task type"
        },
        "task_types": {
          "type": "array",
          "description": "Filter by multiple task types",
          "items": {
            "$ref": "/schemas/3.0.6/enums/task-type.json"
          },
          "minItems": 1
        },
        "created_after": {
          "type": "string",
          "format": "date-time",
          "description": "Filter tasks created after this date (ISO 8601)"
        },
        "created_before": {
          "type": "string",
          "format": "date-time",
          "description": "Filter tasks created before this date (ISO 8601)"
        },
        "updated_after": {
          "type": "string",
          "format": "date-time",
          "description": "Filter tasks last updated after this date (ISO 8601)"
        },
        "updated_before": {
          "type": "string",
          "format": "date-time",
          "description": "Filter tasks last updated before this date (ISO 8601)"
        },
        "task_ids": {
          "type": "array",
          "description": "Filter by specific task IDs",
          "items": {
            "type": "string"
          },
          "minItems": 1,
          "maxItems": 100
        },
        "context_contains": {
          "type": "string",
          "description": "Filter tasks where context contains this text (searches media_buy_id, signal_id, etc.)"
        },
        "has_webhook": {
          "type": "boolean",
          "description": "Filter tasks that have webhook configuration when true"
        }
      },
      "additionalProperties": true
    },
    "sort": {
      "type": "object",
      "description": "Sorting parameters",
      "properties": {
        "field": {
          "type": "string",
          "enum": [
            "created_at",
            "updated_at",
            "status",
            "task_type",
            "protocol"
          ],
          "default": "created_at",
          "description": "Field to sort by"
        },
        "direction": {
          "$ref": "/schemas/3.0.6/enums/sort-direction.json",
          "default": "desc",
          "description": "Sort direction"
        }
      },
      "additionalProperties": true
    },
    "pagination": {
      "$ref": "/schemas/3.0.6/core/pagination-request.json"
    },
    "include_history": {
      "type": "boolean",
      "default": false,
      "description": "Include full conversation history for each task (may significantly increase response size)"
    },
    "context": {
      "$ref": "/schemas/3.0.6/core/context.json"
    },
    "ext": {
      "$ref": "/schemas/3.0.6/core/ext.json"
    }
  },
  "additionalProperties": true,
  "examples": [
    {
      "description": "List all pending tasks across protocols",
      "data": {
        "filters": {
          "statuses": [
            "submitted",
            "working",
            "input-required"
          ]
        }
      }
    },
    {
      "description": "Find media-buy tasks requiring attention",
      "data": {
        "filters": {
          "protocol": "media-buy",
          "statuses": [
            "input-required",
            "failed"
          ]
        },
        "sort": {
          "field": "updated_at",
          "direction": "asc"
        }
      }
    },
    {
      "description": "Recent signal operations",
      "data": {
        "filters": {
          "protocol": "signals",
          "created_after": "2025-01-01T00:00:00Z"
        },
        "pagination": {
          "max_results": 20
        }
      }
    },
    {
      "description": "State reconciliation for specific campaign",
      "data": {
        "filters": {
          "context_contains": "nike_q1_2025"
        },
        "include_history": true
      }
    }
  ]
} as const;

