export const core_UserMatch = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/core/user-match.json",
  "title": "User Match",
  "description": "User identifiers for attribution matching. Supports universal IDs, hashed identifiers, click IDs, and probabilistic matching.",
  "type": "object",
  "properties": {
    "uids": {
      "type": "array",
      "description": "Universal ID values for user matching",
      "items": {
        "type": "object",
        "properties": {
          "type": {
            "$ref": "/schemas/3.0.6/enums/uid-type.json",
            "description": "Universal ID type"
          },
          "value": {
            "type": "string",
            "description": "Universal ID value"
          }
        },
        "required": [
          "type",
          "value"
        ],
        "additionalProperties": true
      },
      "minItems": 1
    },
    "hashed_email": {
      "type": "string",
      "description": "SHA-256 hash of lowercase, trimmed email address. Buyer must normalize before hashing: lowercase, trim whitespace. Pseudonymous PII, not anonymous — the email namespace is small enough that an unsalted SHA-256 is recoverable via precomputed dictionaries. Treat as PII for retention, consent, and access-control purposes. See docs/reference/privacy-considerations#unsalted-hashed-identifiers-are-pseudonymous-not-anonymous.",
      "pattern": "^[a-f0-9]{64}$"
    },
    "hashed_phone": {
      "type": "string",
      "description": "SHA-256 hash of E.164-formatted phone number (e.g. +12065551234). Buyer must normalize to E.164 before hashing. Pseudonymous PII, not anonymous — the E.164 namespace is small enough that an unsalted SHA-256 is recoverable via precomputed dictionaries. Treat as PII for retention, consent, and access-control purposes. See docs/reference/privacy-considerations#unsalted-hashed-identifiers-are-pseudonymous-not-anonymous.",
      "pattern": "^[a-f0-9]{64}$"
    },
    "click_id": {
      "type": "string",
      "description": "Platform click identifier (fbclid, gclid, ttclid, ScCid, etc.)"
    },
    "click_id_type": {
      "type": "string",
      "description": "Type of click identifier (e.g. fbclid, gclid, ttclid, msclkid, ScCid)"
    },
    "client_ip": {
      "type": "string",
      "description": "Client IP address for probabilistic matching"
    },
    "client_user_agent": {
      "type": "string",
      "description": "Client user agent string for probabilistic matching"
    },
    "ext": {
      "$ref": "/schemas/3.0.6/core/ext.json"
    }
  },
  "anyOf": [
    {
      "required": [
        "uids"
      ]
    },
    {
      "required": [
        "hashed_email"
      ]
    },
    {
      "required": [
        "hashed_phone"
      ]
    },
    {
      "required": [
        "click_id"
      ]
    },
    {
      "required": [
        "client_ip",
        "client_user_agent"
      ]
    }
  ],
  "additionalProperties": true
} as const;

