export const core_XEntityTypes = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/core/x-entity-types.json",
  "title": "x-entity types",
  "description": "Registry of valid `x-entity` annotation values. Each value tags a schema field whose contents carry identity of the named entity type. The context-entity lint reads this registry to reject unknown `x-entity` values and to catch mismatches between storyboard capture and consume sites. See docs/contributing/x-entity-annotation.md for authoring guidance. To add a value, PR this file and extend the authoring doc.",
  "type": "string",
  "enum": [
    "advertiser_brand",
    "rights_holder_brand",
    "rights_grant",
    "account",
    "operator",
    "media_buy",
    "package",
    "product",
    "product_pricing_option",
    "vendor_pricing_option",
    "creative",
    "creative_format",
    "audience",
    "signal",
    "signal_activation_id",
    "event_source",
    "collection_list",
    "property_list",
    "catalog",
    "property",
    "media_plan",
    "governance_plan",
    "governance_registry_policy",
    "governance_inline_policy",
    "governance_check",
    "content_standards",
    "task",
    "si_session",
    "offering"
  ],
  "x-entity-definitions": {
    "advertiser_brand": "A brand in an advertiser's house portfolio. Identified by the advertiser — e.g., the `brand_id` on get_brand_identity, the `brand_id` inside core/brand-ref.json (buyer_brand, buyer), and core/account.json `brand`. If you `$ref` core/brand-id.json you are asserting advertiser scope; talent-roster ids must use a separate type even if the string shape is identical.",
    "rights_holder_brand": "A brand in a rights agent's roster (talent, music artist, stock-media owner). Identified by the rights agent — e.g., `brand_id` on get_rights-response items, acquire_rights-response, and the rights-filter `brand_id` on get_rights-request.",
    "rights_grant": "A rights grant identifier covering any lifecycle state (acquired, pending_approval, rejected). `rights_id` across brand/* schemas. Named `grant` rather than `contract` because the identifier is issued at request time — a bilateral contract may or may not exist yet.",
    "account": "Billing/scope account in the seller's namespace. `account_id` or the natural-key `{brand, operator}` form; both resolve to the same entity.",
    "operator": "An operator (seller) identity, typically by domain. Distinct from `account` — one operator issues many accounts.",
    "media_buy": "A media buy / campaign. `media_buy_id` across media-buy/* schemas.",
    "package": "A line item within a media buy. `package_id` across media-buy/* schemas.",
    "product": "A seller inventory product. `product_id` across media-buy/* and core/product.json.",
    "product_pricing_option": "A pricing tier on a seller's inventory product (CPM / CPC / CPCV / etc). `pricing_option_id` inside `core/package.json` and `media-buy/package-request.json`. Scoped to the seller's product rate card — not interchangeable with `vendor_pricing_option`.",
    "vendor_pricing_option": "A pricing tier offered by a vendor agent (rights agent, signals agent, creative agent, governance agent) for its own services. `pricing_option_id` via `core/vendor-pricing-option.json`, also surfaced in `brand/acquire-rights-*`, `signals/activate-signal-request`, `media-buy/build-creative-response`, and `creative/get-creative-features-response`. Scoped to the issuing agent; not interchangeable with `product_pricing_option`.",
    "creative": "A creative asset (library entry, buyer-assigned). `creative_id` across creative/*, brand/creative-approval-*, and media-buy/package-request.",
    "creative_format": "A format spec identified by the composite of `agent_url` + `id` (see core/format-id.json).",
    "audience": "A buyer-managed audience (CRM, lookalike seed, suppression). `audience_id` in media-buy/sync-audiences-request.",
    "signal": "A data signal (catalog or agent-native). `signal_id` in signals/* schemas. Opaque activation ids use `signal_activation_id` instead.",
    "signal_activation_id": "Opaque identifier used to activate a signal on a signals agent. `signal_agent_segment_id` in signals/* schemas. Scoped to the signals agent that issued it; not interchangeable with `signal`.",
    "event_source": "A conversion pixel or event feed. `event_source_id` in media-buy/sync-event-sources-request, media-buy/log-event-request, and core/event.json.",
    "collection_list": "A buyer-managed collection list. `list_id` on collection/* schemas.",
    "property_list": "A buyer-managed property list. `list_id` on property/* schemas. Same field name as collection_list — annotation distinguishes them.",
    "catalog": "A buyer catalog feed (product, inventory, promotion, offering). `catalog_id` in media-buy/sync-catalogs-request and core/catalog.json.",
    "property": "A publisher property in the seller's view. Appears in property/* and referenced by core/property.json.",
    "media_plan": "A media plan — distinct from media_buy (a plan can have multiple buys or precede a buy). Reserved for future media-plan schemas; no currently-shipped schemas use this value. Do not confuse with `governance_plan`, which owns every `plan_id` in governance/* schemas today.",
    "governance_plan": "A governance plan (AI Act, consent, suitability). `plan_id` in governance/* schemas, plus media-buy/create-media-buy-request.plan_id (which flows into check_governance).",
    "governance_registry_policy": "A governance policy identifier resolved against the shared AdCP policy registry (e.g., 'uk_hfss', 'us_coppa', 'garm:brand_safety:violence'). Globally unique and stable across organizations. Referenced as `policy_id` in governance/policy-ref.json, governance/sync-plans-request (plans[].policy_ids[], portfolio.shared_policy_ids[]), governance/sync-plans-response (resolved_policies[]), governance/policy-category-definition (regulatory_frameworks[].policy_ids[]), plus property/validation-result, error-details/policy-violation, and content-standards/* result breakdowns. Not interchangeable with `governance_inline_policy` — a registry id fed into an inline consumer (or vice versa) is the kind of cross-namespace conflation this split exists to catch.",
    "governance_inline_policy": "A bespoke, plan-scoped policy authored inline via governance/policy-entry.json. Scoped to the authoring container (plan, portfolio, or content-standards configuration) — the same id string in a different container refers to a different rule. Used for campaign-specific exclusions, custom brand rules, and ad-hoc additions to registry-sourced policies (inline policies can only add restrictions; they cannot relax registry-sourced enforcement). Every `$ref` to policy-entry.json inside an AdCP task schema is an inline usage — registry policies are served by a separate out-of-band endpoint, not embedded in task payloads.",
    "governance_check": "A governance check result identifier. `check_id` in governance/check-governance-response and governance/report-plan-outcome-request — it round-trips between the two, so entity-identity tracking is required.",
    "content_standards": "A content-standards document. `standards_id` in content-standards/* schemas.",
    "task": "An async task handle (governance check, validation result). `task_id` across core/tasks-* schemas.",
    "si_session": "A sponsored-intelligence conversation session. `session_id` in sponsored-intelligence/* schemas.",
    "offering": "A brand-published offering (campaign, promotion, product set, service) promoted via traditional creatives or SI conversations. `offering_id` in core/offering.json, sponsored-intelligence/si-get-offering-*, and sponsored-intelligence/si-initiate-session-request. Also appears as a catalog item-type id when `core/catalog.json::type` is `offering`."
  }
} as const;

