export const mediaBuy_SyncCatalogsResponse = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/media-buy/sync-catalogs-response.json",
  "title": "Sync Catalogs Response",
  "description": "Response from catalog sync operation. Returns either per-catalog results (best-effort processing) OR operation-level errors (complete failure). Platforms may approve, reject, or flag individual items within each catalog (similar to Google Merchant Center product review).",
  "type": "object",
  "oneOf": [
    {
      "title": "SyncCatalogsSuccess",
      "description": "Success response - sync operation processed catalogs (may include per-catalog failures)",
      "type": "object",
      "properties": {
        "dry_run": {
          "type": "boolean",
          "description": "Whether this was a dry run (no actual changes made)"
        },
        "catalogs": {
          "type": "array",
          "description": "Results for each catalog processed. Items with action='failed' indicate per-catalog validation/processing failures, not operation-level failures.",
          "items": {
            "type": "object",
            "properties": {
              "catalog_id": {
                "type": "string",
                "description": "Catalog ID from the request",
                "x-entity": "catalog"
              },
              "action": {
                "$ref": "/schemas/3.0.6/enums/catalog-action.json",
                "description": "Action taken for this catalog"
              },
              "platform_id": {
                "type": "string",
                "description": "Platform-specific ID assigned to the catalog"
              },
              "item_count": {
                "type": "integer",
                "minimum": 0,
                "description": "Total number of items in the catalog after sync. Required when action is 'created', 'updated', or 'unchanged'. Omitted on 'failed' and 'deleted'."
              },
              "items_approved": {
                "type": "integer",
                "minimum": 0,
                "description": "Number of items approved by the platform. Populated when the platform performs item-level review."
              },
              "items_pending": {
                "type": "integer",
                "minimum": 0,
                "description": "Number of items pending platform review. Common for product catalogs where items must pass content policy checks."
              },
              "items_rejected": {
                "type": "integer",
                "minimum": 0,
                "description": "Number of items rejected by the platform. Check item_issues for rejection reasons."
              },
              "item_issues": {
                "type": "array",
                "description": "Per-item issues reported by the platform (rejections, warnings). Only present when the platform performs item-level review.",
                "items": {
                  "type": "object",
                  "properties": {
                    "item_id": {
                      "type": "string",
                      "description": "ID of the catalog item with an issue"
                    },
                    "status": {
                      "$ref": "/schemas/3.0.6/enums/catalog-item-status.json",
                      "description": "Item review status"
                    },
                    "reasons": {
                      "type": "array",
                      "description": "Reasons for rejection or warning",
                      "items": {
                        "type": "string"
                      }
                    }
                  },
                  "required": [
                    "item_id",
                    "status"
                  ],
                  "additionalProperties": true
                }
              },
              "last_synced_at": {
                "type": "string",
                "format": "date-time",
                "description": "ISO 8601 timestamp of when the most recent sync was accepted by the platform"
              },
              "next_fetch_at": {
                "type": "string",
                "format": "date-time",
                "description": "ISO 8601 timestamp of when the platform will next fetch the feed URL. Only present for URL-based catalogs with update_frequency."
              },
              "changes": {
                "type": "array",
                "description": "Field names that were modified (only present when action='updated')",
                "items": {
                  "type": "string"
                }
              },
              "errors": {
                "type": "array",
                "description": "Validation or processing errors (only present when action='failed')",
                "items": {
                  "$ref": "/schemas/3.0.6/core/error.json"
                }
              },
              "warnings": {
                "type": "array",
                "description": "Non-fatal warnings about this catalog",
                "items": {
                  "type": "string"
                }
              }
            },
            "required": [
              "catalog_id",
              "action"
            ],
            "additionalProperties": true,
            "allOf": [
              {
                "if": {
                  "properties": {
                    "action": {
                      "enum": [
                        "created",
                        "updated",
                        "unchanged"
                      ]
                    }
                  },
                  "required": [
                    "action"
                  ]
                },
                "then": {
                  "required": [
                    "item_count"
                  ]
                }
              }
            ]
          }
        },
        "sandbox": {
          "type": "boolean",
          "description": "When true, this response contains simulated data from sandbox mode."
        },
        "context": {
          "$ref": "/schemas/3.0.6/core/context.json"
        },
        "ext": {
          "$ref": "/schemas/3.0.6/core/ext.json"
        }
      },
      "required": [
        "catalogs"
      ],
      "additionalProperties": true,
      "not": {
        "required": [
          "errors"
        ]
      }
    },
    {
      "title": "SyncCatalogsError",
      "description": "Error response - operation failed completely, no catalogs were processed",
      "type": "object",
      "properties": {
        "errors": {
          "type": "array",
          "description": "Operation-level errors that prevented processing any catalogs (e.g., authentication failure, service unavailable, invalid request format)",
          "items": {
            "$ref": "/schemas/3.0.6/core/error.json"
          },
          "minItems": 1
        },
        "context": {
          "$ref": "/schemas/3.0.6/core/context.json"
        },
        "ext": {
          "$ref": "/schemas/3.0.6/core/ext.json"
        }
      },
      "required": [
        "errors"
      ],
      "additionalProperties": true,
      "not": {
        "anyOf": [
          {
            "required": [
              "catalogs"
            ]
          },
          {
            "required": [
              "dry_run"
            ]
          },
          {
            "required": [
              "sandbox"
            ]
          }
        ]
      }
    }
  ]
} as const;

export const mediaBuy_SyncEventSourcesRequest = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/media-buy/sync-event-sources-request.json",
  "title": "Sync Event Sources Request",
  "description": "Request parameters for configuring event sources on an account with upsert semantics. Existing event sources matched by event_source_id are updated, new ones are created. When delete_missing is true, buyer-managed event sources on the account not in this request are removed. When event_sources is omitted, the call is discovery-only: it returns all event sources on the account without modification. The response always includes both synced and seller-managed event sources for full visibility.",
  "x-mutates-state": true,
  "type": "object",
  "properties": {
    "adcp_major_version": {
      "type": "integer",
      "description": "The AdCP major version the buyer's payloads conform to. Sellers validate against their supported major_versions and return VERSION_UNSUPPORTED if unsupported. When omitted, the seller assumes its highest supported version.",
      "minimum": 1,
      "maximum": 99
    },
    "idempotency_key": {
      "type": "string",
      "description": "Client-generated unique key for at-most-once execution. `event_source_id` gives resource-level dedup per source, but the sync envelope emits audit events and can trigger downstream pixel provisioning — this key prevents those side effects from firing twice on retry. Also serves as a request ID on discovery-only calls (when `event_sources` is omitted). MUST be unique per (seller, request) pair. Use a fresh UUID v4 for each request.",
      "minLength": 16,
      "maxLength": 255,
      "pattern": "^[A-Za-z0-9_.:-]{16,255}$"
    },
    "account": {
      "$ref": "/schemas/3.0.6/core/account-ref.json",
      "description": "Account to configure event sources for."
    },
    "event_sources": {
      "type": "array",
      "description": "Event sources to sync (create or update). When omitted, the call is discovery-only and returns all existing event sources on the account without modification.",
      "minItems": 1,
      "items": {
        "type": "object",
        "properties": {
          "event_source_id": {
            "type": "string",
            "description": "Unique identifier for this event source",
            "x-entity": "event_source"
          },
          "name": {
            "type": "string",
            "description": "Human-readable name for this event source"
          },
          "event_types": {
            "type": "array",
            "description": "Event types this source handles (e.g. purchase, lead). If omitted, accepts all event types.",
            "items": {
              "$ref": "/schemas/3.0.6/enums/event-type.json"
            },
            "minItems": 1
          },
          "allowed_domains": {
            "type": "array",
            "description": "Domains authorized to send events for this event source",
            "items": {
              "type": "string"
            },
            "minItems": 1
          }
        },
        "required": [
          "event_source_id"
        ],
        "additionalProperties": true
      }
    },
    "delete_missing": {
      "type": "boolean",
      "default": false,
      "description": "When true, event sources not included in this sync will be removed"
    },
    "context": {
      "$ref": "/schemas/3.0.6/core/context.json"
    },
    "ext": {
      "$ref": "/schemas/3.0.6/core/ext.json"
    }
  },
  "required": [
    "idempotency_key",
    "account"
  ],
  "additionalProperties": true
} as const;

