export const property_PropertyListChangedWebhook = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.0.6/property/property-list-changed-webhook.json",
  "title": "Property List Changed Webhook",
  "description": "Webhook notification sent when a property list's resolved properties change. Contains a summary only - recipients must call get_property_list to retrieve the updated properties. This keeps payloads small and avoids redundant data transfer.",
  "type": "object",
  "properties": {
    "idempotency_key": {
      "type": "string",
      "description": "Sender-generated key stable across retries of the same webhook event. Governance agents MUST generate a cryptographically random value (UUID v4 recommended) per distinct list-change event and reuse the same key on every retry. Recipients MUST dedupe by this key, scoped to the authenticated sender identity (HMAC secret or Bearer credential) — keys from different governance agents are independent.",
      "minLength": 16,
      "maxLength": 255,
      "pattern": "^[A-Za-z0-9_.:-]{16,255}$"
    },
    "event": {
      "type": "string",
      "const": "property_list_changed",
      "description": "The event type"
    },
    "list_id": {
      "type": "string",
      "description": "ID of the property list that changed",
      "x-entity": "property_list"
    },
    "list_name": {
      "type": "string",
      "description": "Name of the property list"
    },
    "change_summary": {
      "type": "object",
      "description": "Summary of changes to the resolved list",
      "properties": {
        "properties_added": {
          "type": "integer",
          "description": "Number of properties added since last resolution"
        },
        "properties_removed": {
          "type": "integer",
          "description": "Number of properties removed since last resolution"
        },
        "total_properties": {
          "type": "integer",
          "description": "Total properties in the resolved list"
        }
      },
      "additionalProperties": false
    },
    "resolved_at": {
      "type": "string",
      "format": "date-time",
      "description": "When the list was re-resolved"
    },
    "cache_valid_until": {
      "type": "string",
      "format": "date-time",
      "description": "When the consumer should refresh from the governance agent"
    },
    "signature": {
      "type": "string",
      "description": "Cryptographic signature of the webhook payload, signed with the agent's private key. Recipients MUST verify this signature."
    },
    "ext": {
      "$ref": "/schemas/3.0.6/core/ext.json"
    }
  },
  "required": [
    "idempotency_key",
    "event",
    "list_id",
    "resolved_at",
    "signature"
  ],
  "additionalProperties": false
} as const;

